	// 清除所有高亮
	UFUNCTION(BlueprintCallable, Category = "Hex Grid")
	void ClearAllHighlights();

private:
	// 当前高亮的格子缓存
	TArray<ALFPHexTile*> CurrentHighlightedTiles;
	TArray<ALFPHexTile*> CurrentPathTiles;
	EUnitRange CurrentHighlightRange = EUnitRange::UR_Default;
};

