164→bool ALFPHexGridManager::RemoveTile(int32 Q, int32 R)
165→{
166→	FIntPoint Key(Q, R);
167→	if (ALFPHexTile** Found = GridMap.Find(Key))
168→	{
169→		if (*Found)
170→		{
171→			(*Found)->Destroy();
172→		}
173→		GridMap.Remove(Key);
174→		return true;
175→	}
176→	return false;
177→}
