362→TArray<ALFPHexTile*> ALFPHexGridManager::GetTilesInRange(ALFPHexTile* Center, int32 MaxRange, int32 MinRange)
363→{
364→	TArray<ALFPHexTile*> ReachableTiles;
365→	if (!Center || MaxRange <= 0) return ReachableTiles;
366→
367→	// Dijkstra 数据结构（支持变代价地形）
368→	TMap<ALFPHexTile*, int32> MoveCosts;
369→	TArray<ALFPHexTile*> OpenList;
370→
371→	OpenList.Add(Center);
372→	MoveCosts.Add(Center, 0);
373→
374→	while (OpenList.Num() > 0)
375→	{
376→		// 找到代价最小的节点
377→		int32 MinCostIndex = 0;
378→		int32 MinCost = MoveCosts[OpenList[0]];
379→		for (int32 i = 1; i < OpenList.Num(); i++)
380→		{
381→			int32 Cost = MoveCosts[OpenList[i]];
382→			if (Cost < MinCost)
383→			{
384→				MinCost = Cost;
385→				MinCostIndex = i;
386→			}
387→		}
388→
389→		ALFPHexTile* CurrentTile = OpenList[MinCostIndex];
390→		OpenList.RemoveAt(MinCostIndex);
391→		int32 CurrentCost = MoveCosts[CurrentTile];
392→
393→		// 获取所有邻居
394→		for (ALFPHexTile* Neighbor : GetNeighbors(CurrentTile->GetCoordinates()))
395→		{
396→			if (!Neighbor || !Neighbor->IsWalkable() || Neighbor->IsOccupied()) continue;
397→
398→			// 计算移动代价（使用地形代价）
399→			const int32 NewCost = CurrentCost + Neighbor->GetMovementCost();
400→
401→			// 如果未访问或找到更短路径
402→			if (!MoveCosts.Contains(Neighbor) || NewCost < MoveCosts[Neighbor])
403→			{
404→				MoveCosts.Add(Neighbor, NewCost);
405→
406→				// 在移动范围内才加入开放列表
407→				if (NewCost <= MaxRange)
408→				{
409→					OpenList.Add(Neighbor);
410→				}
411→			}
412→		}
413→	}
414→
415→	// 收集所有可达格子（排除起点，应用最小范围过滤）
416→	for (auto& Pair : MoveCosts)
417→	{
418→		if (Pair.Key != Center && Pair.Value >= MinRange && Pair.Value <= MaxRange)
419→		{
420→			ReachableTiles.Add(Pair.Key);
421→		}
422→	}
423→
424→	return ReachableTiles;
425→}
