437→TArray<ALFPHexTile*> ALFPHexGridManager::FindPath(ALFPHexTile* Start, ALFPHexTile* End)
438→{
439→	TArray<ALFPHexTile*> Path;
440→
441→	// 验证输入有效性
442→	if (!Start || !End || !End->IsWalkable())
443→	{
444→		UE_LOG(LogTemp, Warning, TEXT("FindPath: Invalid start or end tile"));
445→		return Path;
446→	}
447→
448→	// 如果起点和终点相同
449→	if (Start == End) {
450→		Path.Add(Start);
451→		UE_LOG(LogTemp, Log, TEXT("FindPath: Start and end are the same tile"));
452→		return Path;
453→	}
454→
455→	// 寻路数据结构
456→	TMap<ALFPHexTile*, ALFPHexTile*> ParentMap;
457→	TMap<ALFPHexTile*, float> GScoreMap;  // 实际移动代价
458→	TSet<ALFPHexTile*> OpenSet;
459→	TSet<ALFPHexTile*> ClosedSet;
460→
461→	// 初始化起点
462→	OpenSet.Add(Start);
463→	GScoreMap.Add(Start, 0.0f);
464→	ParentMap.Add(Start, nullptr);
465→
466→	bool bPathFound = false;
467→
468→	while (!OpenSet.IsEmpty())
469→	{
470→		// 获取开放集中F值最小的节点
471→		ALFPHexTile* Current = nullptr;
472→		float LowestF = TNumericLimits<float>::Max();
473→
474→		for (ALFPHexTile* Tile : OpenSet)
475→		{
476→			const float G = GScoreMap[Tile];
477→			const float H = FLFPHexCoordinates::Distance(Tile->GetCoordinates(), End->GetCoordinates());
478→			const float F = G + H;
479→
480→			if (F < LowestF)
481→			{
482→				LowestF = F;
483→				Current = Tile;
484→			}
485→		}
486→
487→		// 到达终点
488→		if (Current == End)
489→		{
490→			bPathFound = true;
491→			ALFPHexTile* PathNode = End;
492→			while (PathNode)
493→			{
494→				Path.Add(PathNode);
495→				PathNode = ParentMap[PathNode];
496→			}
497→			Algo::Reverse(Path);
498→			break;
499→		}
500→
501→		// 移动节点到关闭集
502→		OpenSet.Remove(Current);
503→		ClosedSet.Add(Current);
504→
505→		// 遍历所有邻居
506→		for (const FLFPHexCoordinates& Dir : HexDirections)
507→		{
508→			FLFPHexCoordinates NeighborCoords = Current->GetCoordinates();
509→			NeighborCoords.Q += Dir.Q;
510→			NeighborCoords.R += Dir.R;
511→			NeighborCoords.S = -NeighborCoords.Q - NeighborCoords.R;  // 重新计算立方坐标
512→
513→			ALFPHexTile* Neighbor = GetTileAtCoordinates(NeighborCoords);
514→
515→			// 跳过无效邻居
516→			if (!Neighbor ||
517→				!Neighbor->IsWalkable() ||
518→				Neighbor->IsOccupied() ||
519→				ClosedSet.Contains(Neighbor))
520→			{
521→				continue;
522→			}
523→
524→			// 计算新G值（使用地形移动代价）
525→			const float TentativeG = GScoreMap[Current] + (float)Neighbor->GetMovementCost();
526→
527→			// 发现新节点或找到更短路径
528→			if (!OpenSet.Contains(Neighbor) || TentativeG < GScoreMap[Neighbor])
529→			{
530→				ParentMap.Add(Neighbor, Current);
531→				GScoreMap.Add(Neighbor, TentativeG);
532→
533→				if (!OpenSet.Contains(Neighbor)) {
534→					OpenSet.Add(Neighbor);
535→				}
536→			}
537→		}
538→	}
539→
540→	Path.Remove(Start);
541→	// 调试绘制路径
542→	//DrawDebugPath(Path, bPathFound);
543→
544→	if (bPathFound) {
545→		UE_LOG(LogTemp, Log, TEXT("FindPath: Found path with %d tiles"), Path.Num());
546→	}
547→	else {
548→		UE_LOG(LogTemp, Warning, TEXT("FindPath: No valid path found"));
549→	}
550→
551→	return Path;
552→}
