719→// 像素位置转换为六边形坐标
720→FLFPHexCoordinates ALFPHexGridManager::PixelToHexCoordinates(const FVector2D& PixelPosition, float InHexSize)
721→{
722→    // 获取像素值
723→    float x = PixelPosition.X;
724→    float y = PixelPosition.Y;
725→
726→    // 转换为立方坐标 - 尖顶六边形公式
727→    float q = (2.0f / 3.0f) * x;
728→    float r = (-1.0f / 3.0f) * x + (FMath::Sqrt(3.0f) / 3.0f) * y;
729→
730→    // 使用优化后的四舍五入到最近坐标
731→    return RoundToHex(q, r);
732→}
