#include "LFP2D/HexGrid/LFPHexGridManager.h"
#include "LFP2D/HexGrid/LFPTerrainDataAsset.h"
#include "LFP2D/HexGrid/LFPMapData.h"
#include "Engine/World.h"
#include "Engine/DataTable.h"
#include "Kismet/GameplayStatics.h"
#include "LFP2D/Unit/LFPTacticsUnit.h"
#include "DrawDebugHelpers.h"
#include "Misc/FileHelper.h"
#include "Misc/Paths.h"

// 六边形方向常量（平顶六边形布局）
const TArray<FLFPHexCoordinates> ALFPHexGridManager::HexDirections = {
	FLFPHexCoordinates(1, 0),   // 东
	FLFPHexCoordinates(1, -1),  // 东北
	FLFPHexCoordinates(0, -1),  // 西北
	FLFPHexCoordinates(-1, 0),  // 西
	FLFPHexCoordinates(-1, 1),  // 西南
	FLFPHexCoordinates(0, 1)    // 东南
};

// Sets default values
ALFPHexGridManager::ALFPHexGridManager()
{
 	// Set this actor to call Tick() every frame.  You can turn this off to improve performance if you don't need it.
	PrimaryActorTick.bCanEverTick = true;

	HexSize = 100.0f;
	GridWidth = 10;
	GridHeight = 10;
}

// Called when the game starts or when spawned
void ALFPHexGridManager::BeginPlay()
{
	Super::BeginPlay();

	// 如果有预设地图数据表，优先从数据表加载
	/*if (MapDataTable)
	{
		LoadMapFromDataTable(MapDataTable);
	}
	else
	{
		GenerateGrid(GridWidth, GridHeight);
	}*/
}

// Called every frame
void ALFPHexGridManager::Tick(float DeltaTime)
{
	Super::Tick(DeltaTime);

	// 调试绘制网格
	if (bDrawDebug)
	{
		for (auto& TilePair : GridMap)
		{
			if (TilePair.Value)
			{
				FVector Center = TilePair.Value->GetActorLocation();
				DrawDebugHexagon(Center, FColor::Green);

				// 显示坐标
				FLFPHexCoordinates Coords = TilePair.Value->GetCoordinates();
				FString CoordText = FString::Printf(TEXT("(%d,%d)"), Coords.Q, Coords.R);
				DrawDebugString(GetWorld(), Center + FVector(0, 0, 20), CoordText, nullptr, FColor::White, 0, true);
			}
		}
	}
}

void ALFPHexGridManager::GenerateGrid(int32 Width, int32 Height)
{
	ClearGrid();

	// 生成矩形网格
	ELFPTerrainType DefaultType = DefaultTerrainData ? DefaultTerrainData->TerrainType : ELFPTerrainType::TT_Grass;

	for (int32 r = 0; r < Height; r++)
	{
		for (int32 q = 0; q < Width; q++)
		{
			// 计算偏移坐标 - 平顶六边形布局
			int32 offsetQ = q - FMath::FloorToInt(r / 2.0f);
			SpawnTileAt(offsetQ, r, DefaultType);
		}
	}
}

void ALFPHexGridManager::ClearGrid()
{
	for (auto& Tile : GridMap)
	{
		if (Tile.Value)
		{
			Tile.Value->Destroy();
		}
	}
	GridMap.Empty();
}

ALFPHexTile* ALFPHexGridManager::SpawnTileAt(int32 Q, int32 R, ELFPTerrainType TerrainType,
	FName DecorationID, ELFPSpawnFaction SpawnFaction, int32 SpawnIndex, FGameplayTag EventTag)
{
	FIntPoint Key(Q, R);
	// 如果已存在则跳过
	if (GridMap.Contains(Key)) return GridMap[Key];

	FLFPHexCoordinates HexCoord(Q, R);
	FVector WorldLocation = HexCoord.ToWorldLocation(HexSize, VerticalScale) + GetActorLocation();

	FActorSpawnParameters SpawnParams;
	SpawnParams.Owner = this;
	ALFPHexTile* NewTile = GetWorld()->SpawnActor<ALFPHexTile>(
		HexTileClass,
		WorldLocation,
		FRotator::ZeroRotator,
		SpawnParams
	);

	if (!NewTile) return nullptr;

	NewTile->SetCoordinates(HexCoord);
	NewTile->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);

	// 应用地形：优先从注册表查找，否则用默认地形
	if (ULFPTerrainDataAsset* TerrainDA = GetTerrainDataForType(TerrainType))
	{
		NewTile->SetTerrainData(TerrainDA);
	}
	else if (DefaultTerrainData)
	{
		NewTile->SetTerrainData(DefaultTerrainData);
	}

	// 应用装饰
	if (!DecorationID.IsNone())
	{
		NewTile->SetDecorationByID(DecorationID, GetDecorationSprite(DecorationID));
	}

	// 应用出生点和事件数据
	NewTile->SpawnFaction = SpawnFaction;
	NewTile->SpawnIndex = SpawnIndex;
	NewTile->EventTag = EventTag;

	// 初始化边缘和覆盖层组件
	NewTile->InitializeEdgeComponents(EdgeHighlightSprite, RangeOverlaySprite, HexSize, VerticalScale);

	GridMap.Add(Key, NewTile);
	return NewTile;
}

ALFPHexTile* ALFPHexGridManager::AddTile(int32 Q, int32 R)
{
	ELFPTerrainType DefaultType = DefaultTerrainData ? DefaultTerrainData->TerrainType : ELFPTerrainType::TT_Grass;
	return SpawnTileAt(Q, R, DefaultType);
}

bool ALFPHexGridManager::RemoveTile(int32 Q, int32 R)
{
	FIntPoint Key(Q, R);
	if (ALFPHexTile** Found = GridMap.Find(Key))
	{
		if (*Found)
		{
			(*Found)->Destroy();
		}
		GridMap.Remove(Key);
		return true;
	}
	return false;
}

void ALFPHexGridManager::LoadMapFromDataTable(UDataTable* InMapData)
{
	if (!InMapData)
	{
		UE_LOG(LogTemp, Warning, TEXT("LoadMapFromDataTable: DataTable 为空"));
		return;
	}

	ClearGrid();

	TArray<FLFPMapTileRow*> AllRows;
	InMapData->GetAllRows<FLFPMapTileRow>(TEXT("LoadMap"), AllRows);

	for (const FLFPMapTileRow* Row : AllRows)
	{
		if (Row)
		{
			SpawnTileAt(Row->Q, Row->R, Row->TerrainType,
				Row->DecorationID, Row->SpawnFaction, Row->SpawnIndex, Row->EventTag);
		}
	}

	UE_LOG(LogTemp, Log, TEXT("LoadMapFromDataTable: 加载了 %d 个格子"), AllRows.Num());
}

bool ALFPHexGridManager::LoadMapFromCSV(const FString& CSVFilePath)
{
	FString CSVContent;
	if (!FFileHelper::LoadFileToString(CSVContent, *CSVFilePath))
	{
		UE_LOG(LogTemp, Error, TEXT("LoadMapFromCSV: 无法加载文件 %s"), *CSVFilePath);
		return false;
	}

	// 使用临时 DataTable 解析 CSV
	UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
	TempTable->RowStruct = FLFPMapTileRow::StaticStruct();

	TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
	if (Problems.Num() > 0)
	{
		for (const FString& Problem : Problems)
		{
			UE_LOG(LogTemp, Warning, TEXT("CSV 解析问题: %s"), *Problem);
		}
	}

	LoadMapFromDataTable(TempTable);
	return true;
}

bool ALFPHexGridManager::SaveMapToCSV(const FString& CSVFilePath)
{
	// CSV 头部（UE DataTable 格式：第一列为 RowName）
	FString CSVContent = TEXT("---,Q,R,TerrainType,DecorationID,SpawnFaction,SpawnIndex,EventTag\n");

	for (const auto& Pair : GridMap)
	{
		ALFPHexTile* Tile = Pair.Value;
		if (!Tile) continue;

		FLFPHexCoordinates Coord = Tile->GetCoordinates();
		FString RowName = FString::Printf(TEXT("%d_%d"), Coord.Q, Coord.R);

		// 地形类型枚举名
		ELFPTerrainType TType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
		FString TerrainStr = UEnum::GetValueAsString(TType);
		TerrainStr = TerrainStr.RightChop(TerrainStr.Find(TEXT("::")) + 2);

		// 装饰 ID
		FString DecoStr = Tile->DecorationID.IsNone() ? TEXT("") : Tile->DecorationID.ToString();

		// 出生点阵营
		FString SpawnStr = UEnum::GetValueAsString(Tile->SpawnFaction);
		SpawnStr = SpawnStr.RightChop(SpawnStr.Find(TEXT("::")) + 2);

		// 事件标签
		FString EventStr = Tile->EventTag.IsValid() ? Tile->EventTag.ToString() : TEXT("");

		CSVContent += FString::Printf(TEXT("%s,%d,%d,%s,%s,%s,%d,%s\n"),
			*RowName, Coord.Q, Coord.R, *TerrainStr, *DecoStr,
			*SpawnStr, Tile->SpawnIndex, *EventStr);
	}

	// 确保目录存在
	FString Directory = FPaths::GetPath(CSVFilePath);
	if (!FPaths::DirectoryExists(Directory))
	{
		IFileManager::Get().MakeDirectory(*Directory, true);
	}

	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *CSVFilePath,
		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);

	if (bSuccess)
	{
		UE_LOG(LogTemp, Log, TEXT("SaveMapToCSV: 保存 %d 个格子到 %s"), GridMap.Num(), *CSVFilePath);
	}
	else
	{
		UE_LOG(LogTemp, Error, TEXT("SaveMapToCSV: 保存失败 %s"), *CSVFilePath);
	}
	return bSuccess;
}

TArray<FLFPMapTileRow> ALFPHexGridManager::ExportMapData() const
{
	TArray<FLFPMapTileRow> Result;
	for (const auto& Pair : GridMap)
	{
		ALFPHexTile* Tile = Pair.Value;
		if (!Tile) continue;

		FLFPMapTileRow Row;
		FLFPHexCoordinates Coord = Tile->GetCoordinates();
		Row.Q = Coord.Q;
		Row.R = Coord.R;
		Row.TerrainType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
		Row.DecorationID = Tile->DecorationID;
		Row.SpawnFaction = Tile->SpawnFaction;
		Row.SpawnIndex = Tile->SpawnIndex;
		Row.EventTag = Tile->EventTag;
		Result.Add(Row);
	}
	return Result;
}

ULFPTerrainDataAsset* ALFPHexGridManager::GetTerrainDataForType(ELFPTerrainType TerrainType) const
{
	if (const TObjectPtr<ULFPTerrainDataAsset>* Found = TerrainRegistry.Find(TerrainType))
	{
		return *Found;
	}
	return nullptr;
}

UPaperSprite* ALFPHexGridManager::GetDecorationSprite(FName DecorationID) const
{
	if (DecorationID.IsNone()) return nullptr;

	if (const TObjectPtr<UPaperSprite>* Found = DecorationRegistry.Find(DecorationID))
	{
		return *Found;
	}
	return nullptr;
}

TArray<ALFPHexTile*> ALFPHexGridManager::GetSpawnPoints(ELFPSpawnFaction Faction) const
{
	TArray<ALFPHexTile*> Result;
	for (const auto& Pair : GridMap)
	{
		if (Pair.Value && Pair.Value->SpawnFaction == Faction && Pair.Value->SpawnIndex > 0)
		{
			Result.Add(Pair.Value);
		}
	}
	// 按 SpawnIndex 排序
	Result.Sort([](const ALFPHexTile& A, const ALFPHexTile& B)
	{
		return A.SpawnIndex < B.SpawnIndex;
	});
	return Result;
}

TArray<ALFPHexTile*> ALFPHexGridManager::GetNeighbors(const FLFPHexCoordinates& Coords) const
{
	TArray<ALFPHexTile*> Neighbors;

	for (const FLFPHexCoordinates& Dir : HexDirections)
	{
		FLFPHexCoordinates NeighborCoords(Coords.Q + Dir.Q, Coords.R + Dir.R);
		FIntPoint Key(NeighborCoords.Q, NeighborCoords.R);

		if (ALFPHexTile* const* FoundTile = GridMap.Find(Key))
		{
			Neighbors.Add(*FoundTile);
		}
	}

	return Neighbors;
}

TArray<ALFPHexTile*> ALFPHexGridManager::GetTilesInRange(ALFPHexTile* Center, int32 MaxRange, int32 MinRange)
{
	TArray<ALFPHexTile*> ReachableTiles;
	if (!Center || MaxRange <= 0) return ReachableTiles;

	// Dijkstra 数据结构（支持变代价地形）
	TMap<ALFPHexTile*, int32> MoveCosts;
	TArray<ALFPHexTile*> OpenList;

	OpenList.Add(Center);
	MoveCosts.Add(Center, 0);

	while (OpenList.Num() > 0)
	{
		// 找到代价最小的节点
		int32 MinCostIndex = 0;
		int32 MinCost = MoveCosts[OpenList[0]];
		for (int32 i = 1; i < OpenList.Num(); i++)
		{
			int32 Cost = MoveCosts[OpenList[i]];
			if (Cost < MinCost)
			{
				MinCost = Cost;
				MinCostIndex = i;
			}
		}

		ALFPHexTile* CurrentTile = OpenList[MinCostIndex];
		OpenList.RemoveAt(MinCostIndex);
		int32 CurrentCost = MoveCosts[CurrentTile];

		// 获取所有邻居
		for (ALFPHexTile* Neighbor : GetNeighbors(CurrentTile->GetCoordinates()))
		{
			if (!Neighbor || !Neighbor->IsWalkable() || Neighbor->IsOccupied()) continue;

			// 计算移动代价（使用地形代价）
			const int32 NewCost = CurrentCost + Neighbor->GetMovementCost();

			// 如果未访问或找到更短路径
			if (!MoveCosts.Contains(Neighbor) || NewCost < MoveCosts[Neighbor])
			{
				MoveCosts.Add(Neighbor, NewCost);

				// 在移动范围内才加入开放列表
				if (NewCost <= MaxRange)
				{
					OpenList.Add(Neighbor);
				}
			}
		}
	}

	// 收集所有可达格子（排除起点，应用最小范围过滤）
	for (auto& Pair : MoveCosts)
	{
		if (Pair.Key != Center && Pair.Value >= MinRange && Pair.Value <= MaxRange)
		{
			ReachableTiles.Add(Pair.Key);
		}
	}

	return ReachableTiles;
}

ALFPHexTile* ALFPHexGridManager::GetTileAtCoordinates(const FLFPHexCoordinates& Coords) const
{
	FIntPoint Key(Coords.Q, Coords.R);
	if (ALFPHexTile* const* FoundTile = GridMap.Find(Key))
	{
		return *FoundTile;
	}
	return nullptr;
}

TArray<ALFPHexTile*> ALFPHexGridManager::FindPath(ALFPHexTile* Start, ALFPHexTile* End)
{
	TArray<ALFPHexTile*> Path;

	// 验证输入有效性
	if (!Start || !End || !End->IsWalkable())
	{
		UE_LOG(LogTemp, Warning, TEXT("FindPath: Invalid start or end tile"));
		return Path;
	}

	// 如果起点和终点相同
	if (Start == End) {
		Path.Add(Start);
		UE_LOG(LogTemp, Log, TEXT("FindPath: Start and end are the same tile"));
		return Path;
	}

	// 寻路数据结构
	TMap<ALFPHexTile*, ALFPHexTile*> ParentMap;
	TMap<ALFPHexTile*, float> GScoreMap;  // 实际移动代价
	TSet<ALFPHexTile*> OpenSet;
	TSet<ALFPHexTile*> ClosedSet;

	// 初始化起点
	OpenSet.Add(Start);
	GScoreMap.Add(Start, 0.0f);
	ParentMap.Add(Start, nullptr);

	bool bPathFound = false;

	while (!OpenSet.IsEmpty())
	{
		// 获取开放集中F值最小的节点
		ALFPHexTile* Current = nullptr;
		float LowestF = TNumericLimits<float>::Max();

		for (ALFPHexTile* Tile : OpenSet)
		{
			const float G = GScoreMap[Tile];
			const float H = FLFPHexCoordinates::Distance(Tile->GetCoordinates(), End->GetCoordinates());
			const float F = G + H;

			if (F < LowestF)
			{
				LowestF = F;
				Current = Tile;
			}
		}

		// 到达终点
		if (Current == End)
		{
			bPathFound = true;
			ALFPHexTile* PathNode = End;
			while (PathNode)
			{
				Path.Add(PathNode);
				PathNode = ParentMap[PathNode];
			}
			Algo::Reverse(Path);
			break;
		}

		// 移动节点到关闭集
		OpenSet.Remove(Current);
		ClosedSet.Add(Current);

		// 遍历所有邻居
		for (const FLFPHexCoordinates& Dir : HexDirections)
		{
			FLFPHexCoordinates NeighborCoords = Current->GetCoordinates();
			NeighborCoords.Q += Dir.Q;
			NeighborCoords.R += Dir.R;
			NeighborCoords.S = -NeighborCoords.Q - NeighborCoords.R;  // 重新计算立方坐标

			ALFPHexTile* Neighbor = GetTileAtCoordinates(NeighborCoords);

			// 跳过无效邻居
			if (!Neighbor ||
				!Neighbor->IsWalkable() ||
				Neighbor->IsOccupied() ||
				ClosedSet.Contains(Neighbor))
			{
				continue;
			}

			// 计算新G值（使用地形移动代价）
			const float TentativeG = GScoreMap[Current] + (float)Neighbor->GetMovementCost();

			// 发现新节点或找到更短路径
			if (!OpenSet.Contains(Neighbor) || TentativeG < GScoreMap[Neighbor])
			{
				ParentMap.Add(Neighbor, Current);
				GScoreMap.Add(Neighbor, TentativeG);

				if (!OpenSet.Contains(Neighbor)) {
					OpenSet.Add(Neighbor);
				}
			}
		}
	}

	Path.Remove(Start);
	// 调试绘制路径
	//DrawDebugPath(Path, bPathFound);

	if (bPathFound) {
		UE_LOG(LogTemp, Log, TEXT("FindPath: Found path with %d tiles"), Path.Num());
	}
	else {
		UE_LOG(LogTemp, Warning, TEXT("FindPath: No valid path found"));
	}

	return Path;
}

void ALFPHexGridManager::DrawDebugHexagon(const FVector& Center, FColor Color) const
{
	const float AngleStep = 60.0f;
	const float HorizontalRadius = HexSize; // 水平方向半径不变
	const float VerticalRadius = HexSize * VerticalScale; // 垂直方向半径缩放

	// 添加 30° 偏移，使六边形正确朝向
	const float AngleOffset = 30.0f;

	TArray<FVector> Points;
	for (int32 i = 0; i < 6; i++)
	{
		// 添加 30° 偏移
		float Angle = FMath::DegreesToRadians(AngleStep * i + AngleOffset);
		FVector Point(
			Center.X + HorizontalRadius * FMath::Cos(Angle),
			Center.Y + VerticalRadius * FMath::Sin(Angle), // 应用垂直缩放
			Center.Z
		);
		Points.Add(Point);
	}

	// 连接点形成六边形
	for (int32 i = 0; i < 6; i++)
	{
		int32 NextIndex = (i + 1) % 6;
		DrawDebugLine(GetWorld(), Points[i], Points[NextIndex], Color, false, -1, 0, 2);
	}
}

void ALFPHexGridManager::DrawDebugPath(const TArray<ALFPHexTile*>& Path, bool bPathFound)
{
	if (!GetWorld()) return;

	const float DebugDuration = 5.0f; // 显示5秒

	// 绘制起点和终点
	if (Path.Num() > 0) {
		// 起点：绿色球体
		DrawDebugSphere(
			GetWorld(),
			Path[0]->GetActorLocation() + FVector(0, 0, 20),
			15.0f, 12, FColor::Green, false, DebugDuration
		);
	}

	if (bPathFound && Path.Num() > 1) {
		// 终点：蓝色球体
		DrawDebugSphere(
			GetWorld(),
			Path.Last()->GetActorLocation() + FVector(0, 0, 20),
			15.0f, 12, FColor::Blue, false, DebugDuration
		);
	}

	// 绘制路径线段
	for (int32 i = 0; i < Path.Num() - 1; i++)
	{
		FVector StartLoc = Path[i]->GetActorLocation() + FVector(0, 0, 15);
		FVector EndLoc = Path[i + 1]->GetActorLocation() + FVector(0, 0, 15);

		// 路径线：黄色
		DrawDebugLine(
			GetWorld(),
			StartLoc,
			EndLoc,
			FColor::Yellow,
			false,
			DebugDuration,
			0,
			3.0f // 线宽
		);

		// 路径点：黄色球体
		DrawDebugSphere(
			GetWorld(),
			StartLoc,
			10.0f, 8, FColor::Yellow, false, DebugDuration
		);
	}

	// 如果找到路径（但前面已经绘制过了，比如长度为1时）
	if (bPathFound && Path.Num() == 1) {
		DrawDebugSphere(
			GetWorld(),
			Path[0]->GetActorLocation() + FVector(0, 0, 20),
			15.0f, 12, FColor::Blue, false, DebugDuration
		);
	}

	// 寻路失败提示
	if (!bPathFound) {
		// 在起始位置绘制红色X
		FVector StartLoc = Path.Num() > 0 ?
			Path[0]->GetActorLocation() :
			(GetActorLocation() + FVector(0, 0, 100));

		DrawDebugLine(
			GetWorld(),
			StartLoc + FVector(-30, -30, 50),
			StartLoc + FVector(30, 30, 50),
			FColor::Red, false, DebugDuration, 0, 5.0f
		);
		DrawDebugLine(
			GetWorld(),
			StartLoc + FVector(-30, 30, 50),
			StartLoc + FVector(30, -30, 50),
			FColor::Red, false, DebugDuration, 0, 5.0f
		);
	}
}

// 以下是用命中检测获取光标下Tile的函数
ALFPHexTile* ALFPHexGridManager::GetHexTileUnderCursor(const FVector2D& ScreenPosition, APlayerController* PlayerController)
{
	FHitResult Hit;
	bool bHitSuccessful = false;
	bHitSuccessful = PlayerController->GetHitResultUnderCursor(ECollisionChannel::ECC_GameTraceChannel1, true, Hit);
	if (!bHitSuccessful)
	{
		return nullptr;
	}

	// 转换为本地坐标（减去网格原点）
	FVector2D LocalLocation;
	LocalLocation.X = Hit.Location.X - GetActorLocation().X;
	LocalLocation.Y = Hit.Location.Y - GetActorLocation().Y;

	// 计算六边形坐标
	FLFPHexCoordinates HexCoords = FLFPHexCoordinates::FromWorldLocation(
		LocalLocation,
		HexSize,
		VerticalScale
	);

	//UE_LOG(LogTemp, Warning, TEXT("Coor:(%d, %d)"), HexCoords.Q, HexCoords.R);
	// 在GridMap中查找
	FIntPoint Key(HexCoords.Q, HexCoords.R);
	if (GridMap.Contains(Key))
		return GridMap[Key];

	return nullptr;
}

// 世界坐标转换为六边形网格坐标
FVector2D ALFPHexGridManager::WorldToHexGridPosition(const FVector& WorldPosition, float InHexSize, float InVerticalScale)
{
	// 尖顶六边形布局参数
	const float HorizontalSpacing = InHexSize * 1.5f * InVerticalScale; // 水平间距（应用垂直缩放）
	const float VerticalSpacing = InHexSize * FMath::Sqrt(3.0f); // 垂直间距

	// 计算原点位置
	FVector GridOrigin = GetActorLocation();

	// 计算相对于网格原点的位置
	float RelX = WorldPosition.X - GridOrigin.X;
	float RelY = WorldPosition.Y - GridOrigin.Y;

	// 转换为六边形网格坐标（近似）
	return FVector2D(
		RelX / HorizontalSpacing,
		RelY / VerticalSpacing
	);
}

// 像素位置转换为六边形坐标
FLFPHexCoordinates ALFPHexGridManager::PixelToHexCoordinates(const FVector2D& PixelPosition, float InHexSize)
{
    // 获取像素值
    float x = PixelPosition.X;
    float y = PixelPosition.Y;

    // 转换为立方坐标 - 尖顶六边形公式
    float q = (2.0f / 3.0f) * x;
    float r = (-1.0f / 3.0f) * x + (FMath::Sqrt(3.0f) / 3.0f) * y;

    // 使用优化后的四舍五入到最近坐标
    return RoundToHex(q, r);
}

// 判断点是否在六边形内
bool ALFPHexGridManager::IsPointInHexagon(const FVector2D& Point, const FVector2D& Center, float InHexSize)
{
	// 坐标转换为相对于六边形中心的单位向量
	FVector2D relPoint = Point - Center;

	// 尖顶六边形的顶点位置（从0度开始）
	static const TArray<FVector2D> vertices = [] {
		TArray<FVector2D> result;
		for (int i = 0; i < 6; i++) {
			float angle_deg = 60 * i; // 尖顶六边形从0度开始
			float angle_rad = FMath::DegreesToRadians(angle_deg);
			result.Add(FVector2D(FMath::Cos(angle_rad), FMath::Sin(angle_rad)));
		}
		return result;
		}();

	// 判断点是否在六边形内（使用射线法）
	int crossings = 0;
	for (int i = 0; i < 6; i++) {
		int j = (i + 1) % 6;
		FVector2D v1 = vertices[i] * InHexSize;
		FVector2D v2 = vertices[j] * InHexSize;

		// 检测边是否跨越y坐标
		if ((v1.Y > relPoint.Y) != (v2.Y > relPoint.Y)) {
			// 计算交点x坐标
			float intersectX = (v2.X - v1.X) * (relPoint.Y - v1.Y) / (v2.Y - v1.Y) + v1.X;

			// 如果交点在点的右侧
			if (relPoint.X < intersectX) {
				crossings++;
			}
		}
	}

	// 奇数次跨越表示在内部
	return (crossings % 2 == 1);
}

void ALFPHexGridManager::ShowRangeHighlight(const TArray<ALFPHexTile*>& RangeTiles, EUnitRange HexRangeType)
{
	ClearAllHighlights();

	// 建立范围集合用于 O(1) 邻居查找
	TSet<FIntPoint> RangeSet;
	for (ALFPHexTile* Tile : RangeTiles)
	{
		if (Tile)
		{
			FLFPHexCoordinates Coord = Tile->GetCoordinates();
			RangeSet.Add(FIntPoint(Coord.Q, Coord.R));
		}
	}

	FLinearColor EdgeColor = GetEdgeColorForRange(HexRangeType);
	FLinearColor OverlayColor = GetOverlayColorForRange(HexRangeType);

	// 对每个范围格子：设置覆盖层 + 检测边界
	for (ALFPHexTile* Tile : RangeTiles)
	{
		if (!Tile) continue;

		// 显示半透明填充覆盖层
		Tile->ShowRangeOverlay(OverlayColor);

		// 检查 6 个方向的邻居，不在范围内则显示边缘描边
		// HexDirections[i] 的方向角度与 EdgeSprite[i] 的朝向不一致
		// EdgeSprite 按顶点顺序排列（法线从 60° 递增），HexDirections 按方向排列（从 0° 递减）
		// 正确映射：EdgeSpriteIdx = 5 - DirIdx
		FLFPHexCoordinates TileCoord = Tile->GetCoordinates();
		for (int32 DirIdx = 0; DirIdx < 6; DirIdx++)
		{
			FLFPHexCoordinates NeighborCoord(
				TileCoord.Q + HexDirections[DirIdx].Q,
				TileCoord.R + HexDirections[DirIdx].R
			);
			FIntPoint NeighborKey(NeighborCoord.Q, NeighborCoord.R);

			// 邻居不在范围集合中 → 这条边是边界
			if (!RangeSet.Contains(NeighborKey))
			{
				Tile->ShowEdge(5 - DirIdx, EdgeColor);
			}
		}
	}

	CurrentHighlightedTiles = RangeTiles;
	CurrentHighlightRange = HexRangeType;
}

void ALFPHexGridManager::ShowRangeHighlightByCoords(const TArray<FLFPHexCoordinates>& Coords, EUnitRange HexRangeType)
{
	TArray<ALFPHexTile*> Tiles;
	for (const FLFPHexCoordinates& Coord : Coords)
	{
		ALFPHexTile* Tile = GetTileAtCoordinates(Coord);
		if (Tile)
		{
			Tiles.Add(Tile);
		}
	}
	ShowRangeHighlight(Tiles, HexRangeType);
}

void ALFPHexGridManager::ShowPathHighlight(const TArray<ALFPHexTile*>& PathTiles)
{
	// 清除之前的路径高亮
	ClearPathHighlight();

	for (ALFPHexTile* Tile : PathTiles)
	{
		if (Tile)
		{
			Tile->ShowPathOverlay(true, PathOverlayColor);
		}
	}

	CurrentPathTiles = PathTiles;
}

void ALFPHexGridManager::ClearPathHighlight()
{
	for (ALFPHexTile* Tile : CurrentPathTiles)
	{
		if (Tile)
		{
			// 恢复为范围覆盖层（如果该格子仍在范围内）
			Tile->ShowPathOverlay(false);
			if (CurrentHighlightRange != EUnitRange::UR_Default)
			{
				Tile->ShowRangeOverlay(GetOverlayColorForRange(CurrentHighlightRange));
			}
		}
	}
	CurrentPathTiles.Empty();
}

void ALFPHexGridManager::ClearAllHighlights()
{
	// 仅清除已缓存的格子，不遍历全图
	for (ALFPHexTile* Tile : CurrentHighlightedTiles)
	{
		if (Tile)
		{
			Tile->ClearAllHighlights();
		}
	}
	CurrentHighlightedTiles.Empty();

	for (ALFPHexTile* Tile : CurrentPathTiles)
	{
		if (Tile)
		{
			Tile->ClearAllHighlights();
		}
	}
	CurrentPathTiles.Empty();

	CurrentHighlightRange = EUnitRange::UR_Default;
}

FLinearColor ALFPHexGridManager::GetEdgeColorForRange(EUnitRange HexRangeType) const
{
	switch (HexRangeType)
	{
	case EUnitRange::UR_Move:        return MoveEdgeColor;
	case EUnitRange::UR_Attack:      return AttackEdgeColor;
	case EUnitRange::UR_SkillEffect: return SkillEdgeColor;
	default:                         return FLinearColor::Transparent;
	}
}

FLinearColor ALFPHexGridManager::GetOverlayColorForRange(EUnitRange HexRangeType) const
{
	switch (HexRangeType)
	{
	case EUnitRange::UR_Move:        return MoveOverlayColor;
	case EUnitRange::UR_Attack:      return AttackOverlayColor;
	case EUnitRange::UR_SkillEffect: return SkillOverlayColor;
	default:                         return FLinearColor::Transparent;
	}
}

// 优化后的四舍五入到最近六边形坐标
FLFPHexCoordinates ALFPHexGridManager::RoundToHex(float q, float r)
{
	// 转换为立方坐标
	float cube_x = q;
	float cube_z = r;
	float cube_y = -cube_x - cube_z;

	// 分别四舍五入到最近整数
	int32 rx = FMath::RoundToInt(cube_x);
	int32 ry = FMath::RoundToInt(cube_y);
	int32 rz = FMath::RoundToInt(cube_z);

	// 计算四舍五入误差
	float x_diff = FMath::Abs(rx - cube_x);
	float y_diff = FMath::Abs(ry - cube_y);
	float z_diff = FMath::Abs(rz - cube_z);

	// 修正最大误差的分量
	if (x_diff > y_diff && x_diff > z_diff) {
		rx = -ry - rz;
	}
	else if (y_diff > z_diff) {
		ry = -rx - rz;
	}
	else {
		rz = -rx - ry;
	}

	return FLFPHexCoordinates(rx, rz);
}

