	switch (CurrentTool)
	{
	case ELFPMapEditorTool::MET_Terrain:
		if (ULFPTerrainDataAsset* TerrainDA = GM->GetTerrainDataForType(BrushTerrainType))
		{
			Tile->SetTerrainData(TerrainDA);
