 57→void ULFPMapEditorComponent::ApplyToolToTile(ALFPHexTile* Tile)
 58→{
 59→	if (!Tile || !bEditorActive) return;
 60→
 61→	ALFPHexGridManager* GM = GetGridManager();
 62→	if (!GM) return;
 63→
 64→	switch (CurrentTool)
 65→	{
 66→	case ELFPMapEditorTool::MET_Terrain:
 67→		if (ULFPTerrainDataAsset* TerrainDA = GM->GetTerrainDataForType(BrushTerrainType))
 68→		{
 69→			Tile->SetTerrainData(TerrainDA);
 70→		}
 71→		break;
 72→
 73→	case ELFPMapEditorTool::MET_Decoration:
 74→		Tile->SetDecorationByID(BrushDecorationID, GM->GetDecorationSprite(BrushDecorationID));
 75→		break;
 76→
 77→	case ELFPMapEditorTool::MET_SpawnPoint:
 78→		Tile->SpawnFaction = BrushSpawnFaction;
 79→		Tile->SpawnIndex = BrushSpawnIndex;
 80→		break;
 81→
 82→	case ELFPMapEditorTool::MET_Event:
 83→		Tile->EventTag = BrushEventTag;
 84→		break;
 85→
 86→	case ELFPMapEditorTool::MET_RemoveTile:
 87→		{
 88→			FLFPHexCoordinates Coord = Tile->GetCoordinates();
 89→			GM->RemoveTile(Coord.Q, Coord.R);
 90→		}
 91→		break;
 92→
 93→	default:
 94→		break;
 95→	}
 96→}
