667→ALFPHexTile* ALFPHexGridManager::GetHexTileUnderCursor(const FVector2D& ScreenPosition, APlayerController* PlayerController)
668→{
669→	FHitResult Hit;
670→	bool bHitSuccessful = false;
671→	bHitSuccessful = PlayerController->GetHitResultUnderCursor(ECollisionChannel::ECC_GameTraceChannel1, true, Hit);
672→	if (!bHitSuccessful)
673→	{
674→		return nullptr;
675→	}
676→
677→	// 转换为本地坐标（减去网格原点）
678→	FVector2D LocalLocation;
679→	LocalLocation.X = Hit.Location.X - GetActorLocation().X;
680→	LocalLocation.Y = Hit.Location.Y - GetActorLocation().Y;
681→
682→	// 计算六边形坐标
683→	FLFPHexCoordinates HexCoords = FLFPHexCoordinates::FromWorldLocation(
684→		LocalLocation,
685→		HexSize,
686→		VerticalScale
687→	);
688→
689→	//UE_LOG(LogTemp, Warning, TEXT("Coor:(%d, %d)"), HexCoords.Q, HexCoords.R);
690→	// 在GridMap中查找
691→	FIntPoint Key(HexCoords.Q, HexCoords.R);
692→	if (GridMap.Contains(Key))
693→		return GridMap[Key];
694→
695→	return nullptr;
696→}
