774→void ALFPHexGridManager::ShowRangeHighlight(const TArray<ALFPHexTile*>& RangeTiles, EUnitRange HexRangeType)
775→{
776→	ClearAllHighlights();
777→
778→	// 建立范围集合用于 O(1) 邻居查找
779→	TSet<FIntPoint> RangeSet;
780→	for (ALFPHexTile* Tile : RangeTiles)
781→	{
782→		if (Tile)
783→		{
784→			FLFPHexCoordinates Coord = Tile->GetCoordinates();
785→			RangeSet.Add(FIntPoint(Coord.Q, Coord.R));
786→		}
787→	}
788→
789→	FLinearColor EdgeColor = GetEdgeColorForRange(HexRangeType);
790→	FLinearColor OverlayColor = GetOverlayColorForRange(HexRangeType);
791→
792→	// 对每个范围格子：设置覆盖层 + 检测边界
793→	for (ALFPHexTile* Tile : RangeTiles)
794→	{
795→		if (!Tile) continue;
796→
797→		// 显示半透明填充覆盖层
798→		Tile->ShowRangeOverlay(OverlayColor);
799→
800→		// 检查 6 个方向的邻居，不在范围内则显示边缘描边
801→		// HexDirections[i] 的方向角度与 EdgeSprite[i] 的朝向不一致
802→		// EdgeSprite 按顶点顺序排列（法线从 60° 递增），HexDirections 按方向排列（从 0° 递减）
803→		// 正确映射：EdgeSpriteIdx = 5 - DirIdx
804→		FLFPHexCoordinates TileCoord = Tile->GetCoordinates();
805→		for (int32 DirIdx = 0; DirIdx < 6; DirIdx++)
806→		{
807→			FLFPHexCoordinates NeighborCoord(
808→				TileCoord.Q + HexDirections[DirIdx].Q,
809→				TileCoord.R + HexDirections[DirIdx].R
810→			);
811→			FIntPoint NeighborKey(NeighborCoord.Q, NeighborCoord.R);
812→
813→			// 邻居不在范围集合中 → 这条边是边界
814→			if (!RangeSet.Contains(NeighborKey))
815→			{
816→				Tile->ShowEdge(5 - DirIdx, EdgeColor);
817→			}
818→		}
819→	}
820→
821→	CurrentHighlightedTiles = RangeTiles;
822→	CurrentHighlightRange = HexRangeType;
823→}
