204→bool ALFPHexGridManager::LoadMapFromCSV(const FString& CSVFilePath)
205→{
206→	FString CSVContent;
207→	if (!FFileHelper::LoadFileToString(CSVContent, *CSVFilePath))
208→	{
209→		UE_LOG(LogTemp, Error, TEXT("LoadMapFromCSV: 无法加载文件 %s"), *CSVFilePath);
210→		return false;
211→	}
212→
213→	// 使用临时 DataTable 解析 CSV
214→	UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
215→	TempTable->RowStruct = FLFPMapTileRow::StaticStruct();
216→
217→	TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
218→	if (Problems.Num() > 0)
219→	{
220→		for (const FString& Problem : Problems)
221→		{
222→			UE_LOG(LogTemp, Warning, TEXT("CSV 解析问题: %s"), *Problem);
223→		}
224→	}
225→
226→	LoadMapFromDataTable(TempTable);
227→	return true;
228→}
